#!/usr/bin/env python3
"""Generate Aura Guide l10n Dart string maps."""
from __future__ import annotations

import base64
import json
import pathlib
import zlib

ROOT = pathlib.Path(__file__).resolve().parent.parent
OUT_DIR = ROOT / "lib" / "l10n"
_PAYLOAD = ''


def _catalog() -> dict[str, dict[str, str]]:
    raw = zlib.decompress(base64.b64decode(_PAYLOAD))
    return json.loads(raw.decode("utf-8"))


def _dart_escape(value: str) -> str:
    return value.replace("\\", "\\\\").replace("$", "\\$").replace("'", "\\'")


def _write_dart(path: pathlib.Path, map_name: str, data: dict[str, str]) -> None:
    lines = [
        "// GENERATED FILE - do not edit by hand.",
        "// Run: python tool/generate_l10n.py",
        "",
        "const Map<String, String> " + map_name + " = <String, String>{",
    ]
    for key in sorted(data):
        lines.append("  '" + key + "': '" + _dart_escape(data[key]) + "',")
    lines.append("};")
    lines.append("")
    path.write_text("\n".join(lines), encoding="utf-8")


def main() -> None:
    catalog = _catalog()
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    _write_dart(OUT_DIR / "strings_en.dart", "stringsEn", catalog["en"])
    _write_dart(OUT_DIR / "strings_ms.dart", "stringsMs", catalog["ms"])
    _write_dart(OUT_DIR / "strings_zh.dart", "stringsZh", catalog["zh"])
    print("Wrote", len(catalog["en"]), "keys to", OUT_DIR)


if __name__ == "__main__":
    main()
